#include<stdio.h>
#include<string.h>
char v[10001][12];int n=0,L[10001],R[10001];
int h(int i){if(i<0||strcmp(v[i],"N")==0)return 0;int lh=h(L[i]),rh=h(R[i]);return 1+(lh>rh?lh:rh);}
int diam(int i){if(i<0||strcmp(v[i],"N")==0)return 0;int lh=h(L[i]),rh=h(R[i]);int c=lh+rh+1;int dl=diam(L[i]),dr=diam(R[i]);return c>dl?(c>dr?c:dr):(dl>dr?dl:dr);}
int main(){while(scanf("%s",v[n])==1)n++;for(int i=0;i<n;i++){L[i]=2*i+1<n?2*i+1:-1;R[i]=2*i+2<n?2*i+2:-1;}printf("%d\n",diam(0));}
